#!/bin/bash

# Script to ensure non-root filesystems are mounted with nodev option on RHEL 8

# Function to get all non-root local filesystems
get_non_root_filesystems() {
    # Get all local filesystem mount points except root, /dev, /sys, /proc, /run, /boot/efi, /boot
    local fstab_file="/etc/fstab"

    # Read fstab and extract non-root local filesystems
    awk '$1 !~ /^#/ && $1 !~ /^$/ && $3 !~ /^(tmpfs|devtmpfs|sysfs|proc|cgroup|efivarfs)$/ && $2 !~ /^\/(dev|sys|proc|run|boot\/efi)?$/ {print $2}' "$fstab_file" 2>/dev/null
}

# Function to check if a mount point has nodev option
has_nodev_option() {
    local mount_point="$1"
    mount | grep "on $mount_point type" | grep -q "nodev"
    return $?
}

# Function to add nodev to fstab if needed
add_nodev_to_fstab() {
    local mount_point="$1"
    local fstab_file="/etc/fstab"

    # Create backup
    cp "$fstab_file" "${fstab_file}.backup.$(date +%s)"

    # Find the line with this mount point and add nodev to options
    sed -i "^$mount_point[[:space:]]/s/\([[:space:]]*[[:space:]]\)\([^[:space:]]*\)\([[:space:]]*[0-9]*[[:space:]]*[0-9]*\)$/\1\2,nodev\3/" "$fstab_file"

    # If the above didn't work (mount point might have special characters), try with awk
    if ! grep "$mount_point" "$fstab_file" | grep -q "nodev"; then
        awk -v mp="$mount_point" '{
            if ($2 == mp) {
                # Split options by comma
                split($4, opts, ",");
                new_opts = "";
                has_nodev = 0;
                for (i in opts) {
                    if (opts[i] == "nodev") {
                        has_nodev = 1;
                    }
                }
                if (has_nodev == 0) {
                    if (new_opts == "") {
                        $4 = $4 ",nodev";
                    } else {
                        $4 = new_opts;
                    }
                }
            }
            print;
        }' "$fstab_file" > "${fstab_file}.tmp"
        mv "${fstab_file}.tmp" "$fstab_file"
    fi
}

# Function to remount filesystem with nodev
remount_with_nodev() {
    local mount_point="$1"

    # Get current mount options
    local current_options=$(mount | grep "on $mount_point type" | sed 's/.*(\(.*\))/\1/')

    # Check if nodev is already there
    if echo "$current_options" | grep -q "nodev"; then
        return 0
    fi

    # Add nodev to options
    mount -o remount,"$current_options",nodev "$mount_point" 2>/dev/null
    return $?
}

# Main execution
main() {
    local fstab_file="/etc/fstab"

    # Check if fstab exists
    if [[ ! -f "$fstab_file" ]]; then
        echo "Error: $fstab_file not found"
        exit 1
    fi

    # Get all non-root local filesystems
    filesystems=$(get_non_root_filesystems)

    if [[ -z "$filesystems" ]]; then
        echo "No non-root local filesystems found to configure"
        exit 0
    fi

    echo "Processing non-root local filesystems..."

    # Process each filesystem
    while IFS= read -r mount_point; do
        [[ -z "$mount_point" ]] && continue

        echo "Processing: $mount_point"

        # Escape special characters for sed
        escaped_mount=$(echo "$mount_point" | sed 's/[\/&]/\\&/g')

        # Check if mount point exists in fstab
        if ! grep -q "^[^#]*[[:space:]]$escaped_mount[[:space:]]" "$fstab_file"; then
            echo "  Mount point not found in fstab"
            continue
        fi

        # Check if nodev is already in fstab for this mount point
        if grep "^[^#]*[[:space:]]$escaped_mount[[:space:]]" "$fstab_file" | grep -q "nodev"; then
            echo "  Already has nodev option in fstab"
        else
            echo "  Adding nodev option to fstab"
            # Use a more robust method to add nodev
            awk -v mp="$mount_point" '
            $2 == mp && $0 !~ /^#/ {
                # Check if options field already has nodev
                if ($4 !~ /nodev/) {
                    if ($4 ~ /,/) {
                        $4 = $4 ",nodev"
                    } else {
                        $4 = $4 ",nodev"
                    }
                }
            }
            {print}
            ' "$fstab_file" > "${fstab_file}.tmp"
            mv "${fstab_file}.tmp" "$fstab_file"
        fi

        # Remount if filesystem is currently mounted
        if mountpoint -q "$mount_point"; then
            echo "  Remounting with nodev option"
            if remount_with_nodev "$mount_point"; then
                echo "  Successfully remounted"
            else
                echo "  Warning: Could not remount, will take effect at next boot"
            fi
        fi
    done <<< "$filesystems"

    echo "Configuration complete"
}

# Run main function
